    PAGE_SIZE_LIMIT = 10000

    def safe_alias(prefix):
        return "rs_" + "__".join(prefix).replace(" ", "_").lower()

    def related_alias(alias):
        return "rs_src_" + alias

    def aggregate_fn(name):
        fns = {
            "Count": frappe.qb.functions.Count,
            "Sum": frappe.qb.functions.Sum,
            "Avg": frappe.qb.functions.Avg,
            "Min": frappe.qb.functions.Min,
            "Max": frappe.qb.functions.Max,
        }
        return fns.get(name)

    def date_bucket(field, gran):
        DateFormat = frappe.qb.CustomFunction("DATE_FORMAT", ["d", "f"])
        YearFn = frappe.qb.CustomFunction("YEAR", ["d"])
        QuarterFn = frappe.qb.CustomFunction("QUARTER", ["d"])
        YearWeekFn = frappe.qb.CustomFunction("YEARWEEK", ["d", "m"])
        ConcatFn = frappe.qb.CustomFunction("CONCAT", ["a", "b", "c"])
        LV = frappe.qb.LiteralValue
        if gran == "Day":
            return DateFormat(field, LV("'%%Y-%%m-%%d'"))
        if gran == "Week":
            return YearWeekFn(field, LV("3"))
        if gran == "Month":
            return DateFormat(field, LV("'%%Y-%%m'"))
        if gran == "Quarter":
            return ConcatFn(YearFn(field), LV("'-Q'"), QuarterFn(field))
        if gran == "Year":
            return YearFn(field)
        return field

    def cast_value(v, fieldtype):
        if v is None:
            return None
        if fieldtype in ("Int", "Check"):
            return frappe.utils.cint(v)
        if fieldtype in ("Float", "Currency", "Percent"):
            return frappe.utils.flt(v)
        if fieldtype == "Date":
            return frappe.utils.getdate(v)
        if fieldtype == "Datetime":
            return frappe.utils.get_datetime(v)
        return frappe.utils.cstr(v)

    def escape_like(value):
        bs = chr(92)
        s = value or ""
        s = s.replace(bs, bs + bs)
        s = s.replace("%", bs + "%")
        s = s.replace("_", bs + "_")
        return s

    def filter_predicate(field, op, value, value_to, value_list, fieldtype):
        if op == "Equals":
            return field == cast_value(value, fieldtype)
        if op == "Not Equals":
            return field != cast_value(value, fieldtype)
        if op == "Greater Than":
            return field > cast_value(value, fieldtype)
        if op == "Less Than":
            return field < cast_value(value, fieldtype)
        if op == "Between":
            return field.between(cast_value(value, fieldtype), cast_value(value_to, fieldtype))
        if op == "Is Set":
            return field.isnotnull() & (field != "")
        if op == "Is Not Set":
            return field.isnull() | (field == "")
        if op == "Contains":
            return field.like("%" + escape_like(frappe.utils.cstr(value)) + "%")
        if op == "Does Not Contain":
            return field.not_like("%" + escape_like(frappe.utils.cstr(value)) + "%")
        if op in ("In", "Not In"):
            items = []
            for p in (value_list or "").split(","):
                p = p.strip()
                if p:
                    items.append(cast_value(p, fieldtype))
            if not items:
                frappe.throw("Filter value list is empty.")
            if op == "In":
                return field.isin(items)
            return field.notin(items)
        frappe.throw("Unknown filter operator: " + str(op))

    def apply_match_op(left, op, right):
        if op == "=":
            return left == right
        if op == "!=":
            return left != right
        if op == ">":
            return left > right
        if op == ">=":
            return left >= right
        if op == "<":
            return left < right
        if op == "<=":
            return left <= right
        frappe.throw("Unknown match operator: " + str(op))

    def build_source_tables(cfg):
        base = frappe.qb.DocType(cfg["base_doctype"])
        tables = {"": (base, cfg["base_doctype"])}
        for rs in cfg.get("related_sources") or []:
            alias = rs["alias"]
            tables[alias] = (
                frappe.qb.DocType(rs["related_doctype"]).as_(related_alias(alias)),
                rs["related_doctype"],
            )
        return tables

    def collect_paths(cfg):
        paths = set()
        def add(src, path):
            if path:
                paths.add(((src or ""), path))
        for c in cfg.get("columns") or []:
            if not c.get("calculation_alias"):
                add(c.get("source"), c.get("field_path"))
        for f in cfg.get("filters") or []:
            add(f.get("source"), f.get("field_path"))
        for g in cfg.get("group_by") or []:
            add(g.get("source"), g.get("field_path"))
        for s in cfg.get("sort") or []:
            add(s.get("source"), s.get("field_path"))
        for rs in cfg.get("related_sources") or []:
            for cond in rs.get("conditions") or []:
                add(cond.get("left_source"), cond.get("left_path"))
                add(rs.get("alias"), cond.get("right_path"))
        for c in cfg.get("calculations") or []:
            for side in ("left", "right"):
                o = (c.get("expression") or {}).get(side) or {}
                if o.get("type") == "field":
                    add(o.get("source"), o.get("path"))
        return paths

    def resolve_link_joins(cfg, tables):
        joins = []
        prefix_table = {(): tables[""][0]}
        prefix_dt = {(): tables[""][1]}

        def ensure(prefix):
            if prefix in prefix_table:
                return prefix_table[prefix]
            parent_prefix = prefix[:-1]
            parent = ensure(parent_prefix)
            parent_dt = prefix_dt[parent_prefix]
            link_fname = prefix[-1]
            df = frappe.get_meta(parent_dt).get_field(link_fname)
            if not df or df.fieldtype != "Link" or not df.options:
                frappe.throw("Cannot traverse link field: " + str(link_fname))
            child_dt = df.options
            alias = safe_alias(prefix)
            child = frappe.qb.DocType(child_dt).as_(alias)
            joins.append((parent, link_fname, child))
            prefix_table[prefix] = child
            prefix_dt[prefix] = child_dt
            return child

        paths = collect_paths(cfg)
        for source, path in sorted(paths):
            if source:
                continue
            segments = tuple(seg for seg in path.split(".") if seg)
            for i in range(1, len(segments)):
                ensure(segments[:i])

        col_refs = {}
        for source, path in paths:
            if source:
                col_refs[(source, path)] = tables[source][0][path]
                continue
            segments = tuple(seg for seg in path.split(".") if seg)
            if len(segments) == 1:
                col_refs[("", path)] = tables[""][0][segments[0]]
            else:
                col_refs[("", path)] = prefix_table[segments[:-1]][segments[-1]]
        return (joins, col_refs)

    def build_query(cfg, count_only=False):
        tables = build_source_tables(cfg)
        base = tables[""][0]
        rl = resolve_link_joins(cfg, tables)
        joins = rl[0]
        col_refs = rl[1]

        q = frappe.qb.from_(base)
        for parent, link_fname, child in joins:
            q = q.left_join(child).on(parent[link_fname] == child.name)
        for rs in cfg.get("related_sources") or []:
            right_tbl = tables[rs["alias"]][0]
            on_clause = None
            for cond in rs.get("conditions") or []:
                left_field = col_refs[((cond.get("left_source") or ""), cond["left_path"])]
                right_field = right_tbl[cond["right_path"]]
                cc = apply_match_op(left_field, cond.get("operator") or "=", right_field)
                if on_clause is None:
                    on_clause = cc
                else:
                    on_clause = on_clause & cc
            if on_clause is None:
                continue
            if (rs.get("join_type") or "Left Join") == "Inner Join":
                q = q.inner_join(right_tbl).on(on_clause)
            else:
                q = q.left_join(right_tbl).on(on_clause)
        for f in cfg.get("filters") or []:
            field = col_refs[((f.get("source") or ""), f["field_path"])]
            q = q.where(filter_predicate(field, f["operator"], f.get("value"),
                f.get("value_to"), f.get("value_list"), f.get("fieldtype") or "Data"))
        if cfg.get("group_by"):
            for g in cfg["group_by"]:
                field = col_refs[((g.get("source") or ""), g["field_path"])]
                q = q.groupby(date_bucket(field, g.get("granularity") or ""))

        if count_only:
            if cfg.get("group_by"):
                inner = q.select(frappe.qb.LiteralValue("1"))
                return frappe.qb.from_(inner.as_("rs_sub")).select(frappe.qb.functions.Count("*"))
            return q.select(frappe.qb.functions.Count("*"))

        group_buckets = {}
        for g in cfg.get("group_by") or []:
            group_buckets[((g.get("source") or ""), g["field_path"])] = g.get("granularity") or ""
        real_cols = []
        for c in cfg.get("columns") or []:
            if not c.get("calculation_alias"):
                real_cols.append(c)
        selects = []
        hidden_keys = []
        included = set()
        for c in real_cols:
            key = ((c.get("source") or ""), c["field_path"])
            included.add(key)
            field = col_refs[key]
            if c.get("aggregate"):
                fn = aggregate_fn(c["aggregate"])
                selects.append(fn(field))
            elif key in group_buckets and group_buckets[key]:
                selects.append(date_bucket(field, group_buckets[key]))
            else:
                selects.append(field)
        if not cfg.get("group_by"):
            for c in cfg.get("calculations") or []:
                for side in ("left", "right"):
                    o = (c.get("expression") or {}).get(side) or {}
                    if o.get("type") == "field":
                        key = ((o.get("source") or ""), (o.get("path") or ""))
                        if key not in included and key in col_refs:
                            selects.append(col_refs[key])
                            included.add(key)
                            hidden_keys.append(key)
        if not selects:
            for g in cfg.get("group_by") or []:
                field = col_refs[((g.get("source") or ""), g["field_path"])]
                selects.append(date_bucket(field, g.get("granularity") or ""))
        for sel in selects:
            q = q.select(sel)
        for s in cfg.get("sort") or []:
            field = col_refs[((s.get("source") or ""), s["field_path"])]
            if s.get("direction") == "Ascending":
                order = frappe.qb.Order.asc
            else:
                order = frappe.qb.Order.desc
            q = q.orderby(field, order=order)
        return (q, hidden_keys, real_cols)

    def eval_calc(expr, lookup):
        if not expr:
            return None
        op = expr.get("op")
        def operand(o):
            if not o:
                return None
            if o.get("type") == "const":
                return o.get("value")
            return lookup.get(((o.get("source") or ""), (o.get("path") or "")))
        l = operand(expr.get("left"))
        r = operand(expr.get("right"))
        if l is None or r is None:
            return None
        l = frappe.utils.flt(l)
        r = frappe.utils.flt(r)
        if op == "+":
            return l + r
        if op == "-":
            return l - r
        if op == "*":
            return l * r
        if op == "/":
            if r == 0:
                return None
            return l / r
        return None

    def aggregate_values(values, name):
        if not values:
            return 0
        if name == "Sum":
            return sum(values)
        if name == "Avg":
            return sum(values) / len(values)
        if name == "Min":
            return min(values)
        if name == "Max":
            return max(values)
        if name == "Count":
            return len(values)
        return sum(values)

    def column_fname(c):
        if c.get("calculation_alias"):
            return "calc__" + c["calculation_alias"]
        src = c.get("source") or ""
        path = (c.get("field_path") or "").replace(".", "__")
        if src:
            return src + "__" + path
        return path

    def column_meta(cfg):
        out = []
        calc_index = {}
        for k in cfg.get("calculations") or []:
            calc_index[k["alias"]] = k
        for c in cfg.get("columns") or []:
            if c.get("calculation_alias"):
                calc = calc_index.get(c["calculation_alias"])
                ftype_map = {
                    "Currency": "Currency",
                    "Percent": "Percent",
                    "Integer": "Int",
                    "Number": "Float",
                }
                fmt = (calc or {}).get("format_type") or "Number"
                ftype = ftype_map.get(fmt, "Float")
                if calc and (calc.get("label") or calc.get("alias")):
                    fallback_label = calc.get("label") or calc["alias"]
                else:
                    fallback_label = c["calculation_alias"]
                label = c.get("label") or fallback_label
                out.append({
                    "fieldname": column_fname(c),
                    "label": label,
                    "fieldtype": ftype,
                    "options": "",
                    "width": c.get("width") or 160,
                })
                continue
            ftype = c.get("fieldtype") or "Data"
            if c.get("aggregate") == "Count":
                ftype = "Int"
            elif c.get("aggregate") in ("Sum", "Avg") and ftype != "Currency":
                ftype = "Float"
            out.append({
                "fieldname": column_fname(c),
                "label": c.get("label") or c.get("field_path") or "",
                "fieldtype": ftype,
                "options": c.get("link_doctype") or c.get("options") or "",
                "width": c.get("width") or 160,
            })
        return out

    def shape_rows(cfg, raw_rows, real_cols, hidden_keys):
        calc_index = {}
        for c in cfg.get("calculations") or []:
            calc_index[c["alias"]] = c
        real_count = len(real_cols)
        out = []
        keys_in_order = []
        for c in real_cols:
            keys_in_order.append(((c.get("source") or ""), c["field_path"]))
        for k in hidden_keys:
            keys_in_order.append(k)
        for raw in raw_rows:
            raw = list(raw)
            lookup = {}
            i = 0
            while i < len(keys_in_order) and i < len(raw):
                lookup[keys_in_order[i]] = raw[i]
                i = i + 1
            real_values = raw[:real_count]
            row_dict = {}
            ri_idx = 0
            for c in cfg.get("columns") or []:
                if c.get("calculation_alias"):
                    calc = calc_index.get(c["calculation_alias"])
                    expr = (calc or {}).get("expression")
                    row_dict[column_fname(c)] = eval_calc(expr, lookup)
                else:
                    if ri_idx < len(real_values):
                        row_dict[column_fname(c)] = real_values[ri_idx]
                    else:
                        row_dict[column_fname(c)] = None
                    ri_idx = ri_idx + 1
            out.append(row_dict)
        return out

    def compute_chart(cfg, rows):
        for ch in cfg.get("charts") or []:
            ctype = ch.get("chart_type") or "Bar"
            if ctype == "KPI":
                continue
            x = (ch.get("x_column_id") or "").replace(".", "__").replace(":", "__")
            y = (ch.get("y_column_id") or "").replace(".", "__").replace(":", "__")
            agg = ch.get("y_aggregate") or "Sum"
            if not y:
                continue
            groups = {}
            for row in rows:
                if x:
                    xv = row.get(x)
                else:
                    xv = "Total"
                if xv is None:
                    xs = ""
                else:
                    xs = str(xv)
                yv = row.get(y)
                yn = None
                if yv is not None:
                    try:
                        yn = float(yv)
                    except Exception:
                        yn = None
                bucket = groups.setdefault(xs, [])
                if yn is not None:
                    bucket.append(yn)
                elif agg == "Count":
                    bucket.append(0)
            labels = list(groups.keys())
            values = []
            for k in labels:
                values.append(round(aggregate_values(groups[k], agg), 2))
            ctype_lower = ctype.lower()
            if ctype_lower not in ("bar", "line", "pie"):
                ctype_lower = "bar"
            return {
                "data": {
                    "labels": labels,
                    "datasets": [{"name": ch.get("title") or y, "values": values}],
                },
                "type": ctype_lower,
                "height": 280,
            }
        return None

    def compute_summary(cfg, rows):
        out = []
        for ch in cfg.get("charts") or []:
            if (ch.get("chart_type") or "") != "KPI":
                continue
            y = (ch.get("y_column_id") or "").replace(".", "__").replace(":", "__")
            if not y:
                continue
            agg = ch.get("y_aggregate") or "Sum"
            vals = []
            for row in rows:
                v = row.get(y)
                if v is None:
                    continue
                try:
                    vals.append(float(v))
                except Exception:
                    pass
            if not vals and agg != "Count":
                value = 0
            else:
                if vals:
                    value = aggregate_values(vals, agg)
                else:
                    placeholder = []
                    for ix in range(len(rows)):
                        placeholder.append(0)
                    value = aggregate_values(placeholder, agg)
            if isinstance(value, (int, float)):
                value = round(value, 2)
            out.append({
                "label": ch.get("title") or y,
                "value": value,
                "datatype": "Float",
                "indicator": "Blue",
            })
        if out:
            return out
        return None

    built = build_query(CONFIG)
    data_q = built[0]
    hidden_keys = built[1]
    real_cols = built[2]
    raw_rows = data_q.limit(PAGE_SIZE_LIMIT).run(as_dict=False) or []
    columns = column_meta(CONFIG)
    rows = shape_rows(CONFIG, raw_rows, real_cols, hidden_keys)
    chart = compute_chart(CONFIG, rows)
    summary = compute_summary(CONFIG, rows)
    return (columns, rows, None, chart, summary)


data = run(CONFIG)
